from dataclasses import dataclass

@dataclass
class RetrievedChunk:
    doc_id: str
    title: str
    url: str
    chunk_text: str
    retrieval_score: float

@dataclass
class AttributedClaim:
    claim_text: str
    source_doc_id: str    # which retrieved chunk supports this claim
    confidence: float     # model's self-reported confidence [0, 1]
    verbatim: bool        # True if the claim is a direct quote

@dataclass
class AttributedResponse:
    answer: str
    claims: list[AttributedClaim]
    sources: list[RetrievedChunk]

    def unsupported_claims(self) -> list[AttributedClaim]:
        """Claims with no matching retrieved chunk — possible hallucinations."""
        source_ids = {s.doc_id for s in self.sources}
        return [c for c in self.claims if c.source_doc_id not in source_ids]

    def citation_block(self) -> str:
        """Render a citation list for display to end users."""
        lines = ["**Sources:**"]
        for i, src in enumerate(self.sources, 1):
            lines.append(f"[{i}] {src.title} — {src.url}")
        return "\n".join(lines)


# Prompting pattern: ask the model to return structured attribution
ATTRIBUTION_SYSTEM = """When answering, identify which specific retrieved document supports each claim.
Return your answer in the following JSON schema:
{
  "answer": "<your complete answer>",
  "claims": [
    {"claim_text": "...", "source_doc_id": "...", "confidence": 0.95, "verbatim": false}
  ]
}"""
